interface AdminMetricCardProps {
  label:     string;
  value:     string;
  sub?:      string;
  accent?:   'green' | 'red' | 'amber' | 'indigo' | 'default';
  icon?:     React.ReactNode;
}

const ACCENT_MAP = {
  green:  'text-emerald-400',
  red:    'text-red-400',
  amber:  'text-amber-400',
  indigo: 'text-indigo-400',
  default:'text-zinc-100',
};

export function AdminMetricCard({ label, value, sub, accent = 'default', icon }: AdminMetricCardProps) {
  return (
    <div className="rounded-xl border border-[#1e1e32] bg-[#0f0f1a] p-5 flex flex-col gap-3">
      <div className="flex items-center justify-between">
        <p className="text-[10px] font-semibold uppercase tracking-widest text-zinc-600">{label}</p>
        {icon && <span className="text-zinc-700">{icon}</span>}
      </div>
      <div>
        <p className={`font-mono text-2xl font-semibold leading-none ${ACCENT_MAP[accent]}`}>
          {value}
        </p>
        {sub && <p className="mt-1.5 text-[11px] text-zinc-700">{sub}</p>}
      </div>
    </div>
  );
}
