'use client';

import { useState } from 'react';
import type { Transaction } from '@/types';
import { StatusBadge } from '@/components/ui/StatusBadge';
import { formatCurrency, formatRelativeTime, formatFullDate, getInitials } from '@/lib/formatters';

interface AdminTransactionRowProps {
  transaction: Transaction;
}

export function AdminTransactionRow({ transaction }: AdminTransactionRowProps) {
  const [expanded, setExpanded] = useState(false);

  const {
    id, userId, recipientName, recipientBank, recipientAccount,
    senderAmount, senderCurrency, receiverAmount, receiverCurrency,
    exchangeRate, status, createdAt, updatedAt,
    narration, failureReason, txHash,
  } = transaction;

  const initials = getInitials(recipientName);
  const hue = recipientName.split('').reduce((acc, c) => acc + c.charCodeAt(0), 0) % 360;

  return (
    <div className={`rounded-xl border bg-[#0f0f1a] transition-all duration-150 ${expanded ? 'border-[#2a2a45]' : 'border-[#1e1e32] hover:border-[#242438]'}`}>
      <button
        type="button"
        onClick={() => setExpanded((p) => !p)}
        className="w-full grid grid-cols-[auto_1fr_auto_auto_auto] items-center gap-4 px-4 py-3.5 text-left"
      >
        {/* Avatar */}
        <div
          className="flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full text-[10px] font-bold"
          style={{ background: `hsl(${hue} 60% 15%)`, color: `hsl(${hue} 80% 70%)`, border: `1px solid hsl(${hue} 60% 22%)` }}
        >
          {initials}
        </div>

        {/* Recipient + user */}
        <div className="min-w-0">
          <p className="text-sm font-medium text-zinc-200 truncate">{recipientName}</p>
          <p className="text-[10.5px] text-zinc-700 font-mono truncate">uid: {userId}</p>
        </div>

        {/* Status */}
        <div className="hidden sm:block">
          <StatusBadge status={status} />
        </div>

        {/* Time */}
        <p className="hidden md:block text-[11px] font-mono text-zinc-700 w-16 text-right">
          {formatRelativeTime(createdAt)}
        </p>

        {/* Amount */}
        <div className="text-right flex-shrink-0">
          <p className="text-sm font-mono font-semibold text-red-400">
            -{formatCurrency(senderAmount, senderCurrency)}
          </p>
          <p className="text-[10px] font-mono text-zinc-700">
            ≈ {formatCurrency(receiverAmount, receiverCurrency)}
          </p>
        </div>
      </button>

      {/* Expanded debug view */}
      {expanded && (
        <div className="border-t border-[#1a1a2e] px-4 py-4">
          <p className="text-[10px] font-semibold uppercase tracking-widest text-zinc-700 mb-3">Debug info</p>
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-x-6 gap-y-3 text-[12px]">
            {[
              { label: 'Transaction ID', value: id,                                          mono: true  },
              { label: 'User ID',        value: userId,                                      mono: true  },
              { label: 'Bank',           value: recipientBank                                            },
              { label: 'Account',        value: recipientAccount,                            mono: true  },
              { label: 'Created',        value: formatFullDate(createdAt)                               },
              { label: 'Updated',        value: formatFullDate(updatedAt)                               },
              { label: 'Exchange rate',  value: `₦${exchangeRate.toFixed(2)} / GHS`,        mono: true  },
              { label: 'Sent',           value: formatCurrency(senderAmount, senderCurrency),mono: true  },
              { label: 'Received',       value: formatCurrency(receiverAmount, receiverCurrency), mono: true, green: true },
            ].map((row) => (
              <div key={row.label}>
                <p className="text-[10px] font-semibold uppercase tracking-widest text-zinc-700">{row.label}</p>
                <p className={`mt-0.5 break-all ${row.mono ? 'font-mono' : ''} ${row.green ? 'text-emerald-400' : 'text-zinc-300'}`}>
                  {row.value}
                </p>
              </div>
            ))}

            {narration && (
              <div>
                <p className="text-[10px] font-semibold uppercase tracking-widest text-zinc-700">Narration</p>
                <p className="mt-0.5 text-zinc-300">{narration}</p>
              </div>
            )}

            {txHash && (
              <div className="col-span-2 sm:col-span-3">
                <p className="text-[10px] font-semibold uppercase tracking-widest text-zinc-700">Tx hash (Base L2)</p>
                <p className="mt-0.5 font-mono text-[11px] text-indigo-400 break-all">{txHash}</p>
              </div>
            )}

            {failureReason && (
              <div className="col-span-2 sm:col-span-3">
                <p className="text-[10px] font-semibold uppercase tracking-widest text-zinc-700">Failure reason</p>
                <p className="mt-0.5 text-red-400">{failureReason}</p>
              </div>
            )}
          </div>

          {/* Admin actions */}
          <div className="mt-4 pt-3 border-t border-[#1a1a2e] flex gap-2 flex-wrap">
            {status === 'FAILED' && (
              <button type="button" className="flex items-center gap-1.5 rounded-lg border border-indigo-500/30 bg-indigo-600/10 px-3 py-1.5 text-[11.5px] font-medium text-indigo-400 hover:bg-indigo-600/20 transition-all">
                <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"><polyline points="1 4 1 10 7 10"/><path d="M3.51 15a9 9 0 1 0 .49-3.68"/></svg>
                Retry transfer
              </button>
            )}
            <button type="button" className="flex items-center gap-1.5 rounded-lg border border-[#1e1e32] bg-[#0c0c1a] px-3 py-1.5 text-[11.5px] font-medium text-zinc-500 hover:text-zinc-300 hover:border-[#2a2a45] transition-all">
              <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>
              View user
            </button>
            <button type="button" className="flex items-center gap-1.5 rounded-lg border border-red-500/20 bg-red-500/5 px-3 py-1.5 text-[11.5px] font-medium text-red-400/70 hover:text-red-400 hover:bg-red-500/10 transition-all">
              <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="4.93" y1="4.93" x2="19.07" y2="19.07"/></svg>
              Flag transaction
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
